func TestComponent_SynchronousHierarchy_IncludedBeforeWrite(t *testing.T) {
	tests := []struct {
		name              string
		entityID          string
		expectHierarchy   bool
		expectedTripleMin int // Minimum triples expected (base + hierarchy)
		reason            string
	}{
		{
			name:              "valid_entity",
			entityID:          "c360.platform.robotics.mav1.drone.test001",
			expectHierarchy:   true,
			expectedTripleMin: 4, // 1 base triple + 3 hierarchy membership edges
			reason:            "6-part entity should get hierarchy triples before KV write",
		},
		{
			name:              "container_entity_excluded",
			entityID:          "c360.platform.robotics.mav1.drone.group",
			expectHierarchy:   false,
			expectedTripleMin: 1, // Only base triple, no hierarchy (prevents infinite cascade)
			reason:            "container entities should not get hierarchy edges",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			comp := createTestComponentWithHierarchyConfig(t, true)
			ctx := context.Background()

			require.NoError(t, comp.Initialize())
			require.NoError(t, comp.Start(ctx))
			defer comp.Stop(5 * time.Second)

			// Create entity
			entity := &graph.EntityState{
				ID: tt.entityID,
				Triples: []message.Triple{
					{
						Subject:   tt.entityID,
						Predicate: "entity.type.class",
						Object:    "test.entity",
						Timestamp: time.Now(),
					},
				},
				Version:   1,
				UpdatedAt: time.Now(),
			}

			// Write entity - hierarchy should be applied synchronously
			require.NoError(t, comp.CreateEntity(ctx, entity), tt.reason)

			// Read back from KV - should already contain hierarchy triples
			entry, err := comp.entityBucket.Get(ctx, tt.entityID)
			require.NoError(t, err, "entity should exist in KV bucket")

			var storedEntity graph.EntityState
			err = json.Unmarshal(entry.Value(), &storedEntity)
			require.NoError(t, err)

			// Verify entity was written with hierarchy triples included
			assert.Equal(t, uint64(1), storedEntity.Version, "entity should be version 1 (written once)")
			assert.GreaterOrEqual(t, len(storedEntity.Triples), tt.expectedTripleMin,
				"%s: expected at least %d triples", tt.reason, tt.expectedTripleMin)

			if tt.expectHierarchy {
				// Verify hierarchy membership edges are present
				hierarchyTriples := 0
				for _, triple := range storedEntity.Triples {
					if triple.Context == "inference.hierarchy" {
						hierarchyTriples++
					}
				}
				assert.GreaterOrEqual(t, hierarchyTriples, 3,
					"entity should have at least 3 hierarchy triples (type, system, domain)")
			} else {
				// Verify NO hierarchy edges for container entities
				for _, triple := range storedEntity.Triples {
					assert.NotEqual(t, "inference.hierarchy", triple.Context,
						"container entities should not have hierarchy edges")
				}
			}
		})
	}
}

